import React, { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";

function Topbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const [searchQuery, setSearchQuery] = useState("");

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      // Điều hướng đến trang tìm kiếm hoặc sân bóng
      navigate(`/fields?search=${encodeURIComponent(searchQuery)}`);
    }
  };

  // Lấy tiêu đề trang dựa trên route
  const getPageTitle = () => {
    const path = location.pathname;
    if (path === "/") return "Trang chủ";
    if (path.startsWith("/matches")) return "Tìm trận";
    if (path.startsWith("/fields")) return "Sân bóng";
    if (path.startsWith("/booking")) return "Đặt sân";
    if (path.startsWith("/my-schedule")) return "Lịch của tôi";
    if (path.startsWith("/profile")) return "Hồ sơ của tôi";
    if (path.startsWith("/admin/bookings")) return "Quản lý Booking";
    if (path.startsWith("/admin/fields")) return "Quản lý Sân bóng";
    if (path.startsWith("/admin/matches")) return "Quản lý Trận đấu";
    if (path.startsWith("/admin/users")) return "Quản lý Người dùng";
    return "Đặt Sân Bóng";
  };

  return (
    <header className="topbar">
      <div className="topbar-inner">
        {/* Page Title */}
        <div className="topbar-title">
          <h1>{getPageTitle()}</h1>
        </div>

        {/* Search Bar */}
        <form className="topbar-search" onSubmit={handleSearch}>
          <div className="topbar-search-wrapper">
            <span className="topbar-search-icon">🔍</span>
            <input
              type="text"
              className="topbar-search-input"
              placeholder="Tìm sân bóng, trận..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </form>

        {/* Right Actions */}
        <div className="topbar-actions">
          <button className="topbar-action-btn" title="Thông báo">
            🔔
            <span className="topbar-action-badge">0</span>
          </button>

          <button className="topbar-action-btn" title="Cài đặt">
            ⚙️
          </button>
        </div>
      </div>
    </header>
  );
}

export default Topbar;
